+		parentRecurrence = parent.Recurrence
+	}
+	if scope == scopeSingle || scope == scopeFuture {
+		instanceID, resolveErr := resolveRecurringInstanceID(ctx, svc, calendarID, eventID, c.OriginalStartTime)
