+	if err := svc.Events.Delete(calendarID, targetEventID).Do(); err != nil {
+		return err
+	}
+	if scope == scopeFuture {
+		truncated, truncateErr := truncateRecurrence(parentRecurrence, c.OriginalStartTime)
